# Python Dependency Management Script

import subprocess
import os

def install_packages_with_pip():
    """Install packages using pip and generate requirements.txt with hashes."""
    # Install packages from requirements.txt
    subprocess.check_call([os.sys.executable, '-m', 'pip', 'install', '-r', 'requirements.txt'])
    # Generate requirements.txt with hashes
    subprocess.check_call([os.sys.executable, '-m', 'pip', 'freeze', '--require-hashes', '>', 'requirements.txt'])

def install_packages_with_poetry():
    """Install packages using Poetry and manage the lock file."""
    # Install packages defined in poetry.lock
    subprocess.check_call(['poetry', 'install'])

def update_dependencies_with_pip():
    """Update all dependencies and freeze them with hashes."""
    # Update all packages to the latest version
    subprocess.check_call([os.sys.executable, '-m', 'pip', 'list', '--outdated', '--format=freeze'])
    # Freeze the updated packages
    subprocess.check_call([os.sys.executable, '-m', 'pip', 'freeze', '--require-hashes', '>', 'requirements.txt'])

def update_dependencies_with_poetry():
    """Update all dependencies defined in pyproject.toml."""
    # Update all packages
    subprocess.check_call(['poetry', 'update'])

def main():
    # Check if using Poetry or pip
    use_poetry = os.path.exists('pyproject.toml')
    
    if use_poetry:
        choice = input("Enter 'install' to install with Poetry or 'update' to update: ").strip().lower()
        if choice == 'install':
            install_packages_with_poetry()
        elif choice == 'update':
            update_dependencies_with_poetry()
    else:
        choice = input("Enter 'install' to install with pip or 'update' to update: ").strip().lower()
        if choice == 'install':
            install_packages_with_pip()
        elif choice == 'update':
            update_dependencies_with_pip()

if __name__ == "__main__":
    main()